const data = $input.all();

for (const item of data) {

    let score = 0;

    // Risk Level
    if (item.json.Risk_Level === "Critical") score += 50;
    else if (item.json.Risk_Level === "High") score += 30;
    else if (item.json.Risk_Level === "Medium") score += 15;

    // Procurement Status
    if (item.json.Procurement_Status === "Approval Required")
        score += 20;

    // Procurement Category
    if (item.json.Procurement_Category === "Emergency Purchase")
        score += 15;

    // Supplier Risk
    if (item.json.Supplier_Action === "Immediate Follow-up")
        score += 15;
    else if (item.json.Supplier_Action === "Monitor Supplier")
        score += 8;

    // Lead Time
    if (Number(item.json.Lead_Time_Days) > 20)
        score += 10;

    // Final Score
    item.json.Supplier_Risk_Score = Math.min(score,100);

    // Classification
    if(score >= 80)
        item.json.Supplier_Risk = "Very High";
    else if(score >= 60)
        item.json.Supplier_Risk = "High";
    else if(score >= 40)
        item.json.Supplier_Risk = "Medium";
    else
        item.json.Supplier_Risk = "Low";

}

return data;

const items = $input.all();

// Sort by Supplier Risk Score (Highest first)
items.sort((a, b) => {
  return b.json.Supplier_Risk_Score - a.json.Supplier_Risk_Score;
});

// Keep only Top 10
return items.slice(0, 10);

const items = $input.all();

const totalSuppliers = items.length;

const veryHigh = items.filter(i =>
    i.json.Supplier_Risk === "Very High").length;

const high = items.filter(i =>
    i.json.Supplier_Risk === "High").length;

const medium = items.filter(i =>
    i.json.Supplier_Risk === "Medium").length;

const low = items.filter(i =>
    i.json.Supplier_Risk === "Low").length;

const averageRisk =
items.reduce((sum, i) =>
sum + Number(i.json.Supplier_Risk_Score), 0) / totalSuppliers;

const highestRiskSupplier = items[0].json.Supplier;

const highestWarehouse = items[0].json.Warehouse;

const averageLeadTime =
items.reduce((sum, i) =>
sum + Number(i.json.Lead_Time_Days), 0) / totalSuppliers;

const totalProcurementValue =
items.reduce((sum, i) =>
sum + Number(i.json.Estimated_Order_Value), 0);

return [
