const items = $input.all();

const suppliers = {};

for (const item of items) {

  const supplier = item.json.Supplier;

  if (!suppliers[supplier]) {
    suppliers[supplier] = {
      Supplier: supplier,
      Total_Products: 0,
      Critical_Products: 0,
      High_Products: 0,
      Total_Risk_Score: 0
    };
  }

  suppliers[supplier].Total_Products++;

  if (item.json.Risk_Level === "Critical") {
    suppliers[supplier].Critical_Products++;
  }

  if (item.json.Risk_Level === "High") {
    suppliers[supplier].High_Products++;
  }

  suppliers[supplier].Total_Risk_Score += Number(item.json.Supplier_Risk_Score || 0);
}

const output = [];

for (const supplier in suppliers) {

  const s = suppliers[supplier];

  const avgRisk =
    s.Total_Risk_Score / s.Total_Products;

  let supplierRisk = "";

  if (avgRisk >= 80)
    supplierRisk = "Very High";
  else if (avgRisk >= 60)
    supplierRisk = "High";
  else if (avgRisk >= 40)
    supplierRisk = "Medium";
  else
    supplierRisk = "Low";

  output.push({
    json: {
      Supplier: s.Supplier,
      Total_Products: s.Total_Products,
      Critical_Products: s.Critical_Products,
      High_Products: s.High_Products,
      Supplier_Risk: supplierRisk
    }
  });
}

output.sort((a, b) =>
  b.json.Critical_Products - a.json.Critical_Products
);

return output;
